            cands.append(ik.get("identity"))
        # 1) top-level
        cands.append(interaction_instance.get("identity"))
        ik2 = interaction_instance.get("interaction_kwargs")
        if isinstance(ik2, dict):
            cands.append(ik2.get("identity"))
        # 2) extra_info
        ei = interaction_instance.get("extra_info")
        if isinstance(ei, dict):
            ik3 = ei.get("interaction_kwargs")
            if isinstance(ik3, dict):
                cands.append(ik3.get("identity"))
        # 3) template_input.extra_info
        ti = interaction_instance.get("template_input")
        if isinstance(ti, dict):
            ei2 = ti.get("extra_info")
            if isinstance(ei2, dict):
                ik4 = ei2.get("interaction_kwargs")
                if isinstance(ik4, dict):
                    cands.append(ik4.get("identity"))
        # 4) reward_model.ground_truth (fallback; sometimes identity info is stored here)
        rm = interaction_instance.get("reward_model")
        if isinstance(rm, dict):
            gt = rm.get("ground_truth")
            if isinstance(gt, dict):
                # sometimes gt itself is the identity (flat)
                cands.append(gt)
                # sometimes nested
                ik5 = gt.get("interaction_kwargs")
                if isinstance(ik5, dict):
                    cands.append(ik5.get("identity"))
        # filter None
        return [x for x in cands if x is not None]
    def _pick_identity_for_tool(
        self, interaction_instance: Dict[str, Any], tool_name: str, call_kwargs: Dict[str, Any]
    ) -> Any:
        """
        Given any candidate identity roots, pick the best identity dict for the tool.
        """
        candidates = self._iter_identity_candidates(interaction_instance, call_kwargs)
        # normalize: keep dict candidates only (others may exist; keep last resort)
        dict_candidates = [c for c in candidates if isinstance(c, dict)]
        if not dict_candidates:
            return candidates[0] if candidates else {}
        # For each root, try bucket keys first; then flat.
        for root in dict_candidates:
            # preferred tool-name buckets
            if tool_name in root and isinstance(root[tool_name], dict):
                return root[tool_name]
            # legacy buckets
            for k in self.LEGACY_IDENTITY_KEYS:
                if k in root and isinstance(root[k], dict):
                    return root[k]
            # if root itself looks like a flat identity (has unfixed_parameters), accept it
            if "unfixed_parameters" in root and isinstance(root["unfixed_parameters"], dict):
                return root
        # fallback: first dict candidate
        return dict_candidates[0]
    # ---------------- main ----------------
    async def generate_response(
        self, instance_id: str, messages: list[dict[str, Any]], **kwargs
    ) -> tuple[bool, str, float, dict[str, Any]]:
        interaction_instance = self._instance_dict[instance_id]
        # last assistant content
        content = ""
        for i in range(len(messages) - 1, -1, -1):
            m = messages[i]
            if m.get("role") == "assistant":
                content = m.get("content", "") or ""
                break
        # stop on <END>/<End>/<end>
        if re.search(r"<[Ee][Nn][Dd]>", content):
            return True, "", 0.0, {"simulation_raw_data": {}}
        if not interaction_instance:
            return False, "No interations available", 0.0, {"simulation_raw_data": {}}
        tool_name = self.TOOL_NAME
        try:
            spaces_to_check, space_error = self._extract_parameter_space(content)
            parameter_relation_code, relation_error = self._extract_parameter_relation_code(content)
            if space_error is not None:
                error_result = [{"idx": 0, "result": f"ParameterSpace解析失败: {space_error}"}]
                return False, f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>", 0.0, {
                    "simulation_raw_data": {}
                }
            if relation_error is not None:
                error_result = [{"idx": 0, "result": f"ParameterRelationCode解析失败: {relation_error}"}]
                return False, f"<CheckValid>{json.dumps(error_result, ensure_ascii=False)}</CheckValid>", 0.0, {
                    "simulation_raw_data": {}
                }
            if spaces_to_check is None or parameter_relation_code is None or len(spaces_to_check) == 0:
                return True, "", 0.0, {"simulation_raw_data": {}}
            if tool_name not in self.tool_instances:
                raise RuntimeError(
                    f"Tool '{tool_name}' not registered. available={list(self.tool_instances.keys())}"
                )
            check_valid_instance = self.tool_instances[tool_name]["instance"]
            # ✅ all-in identity pick
            ident_for_tool = self._pick_identity_for_tool(interaction_instance, tool_name, kwargs)
            # guard: if still missing, make error explicit
            if isinstance(ident_for_tool, dict) and "unfixed_parameters" not in ident_for_tool:
                raise RuntimeError(
                    f"identity for {tool_name} missing 'unfixed_parameters'. "
                    f"picked_keys={list(ident_for_tool.keys())}"
                )
            create_kwargs = {"identity": ident_for_tool}
            create_result = await check_valid_instance.create(instance_id, **create_kwargs)
            if isinstance(create_result, tuple):
                current_instance_id, _ = create_result
            else:
                current_instance_id = create_result
            all_results: List[Dict[str, Any]] = []
            simulation_raw_data: Dict[str, Any] = {}
            for parameter_space_dict in spaces_to_check:
                idx = parameter_space_dict.get("idx", 0) if isinstance(parameter_space_dict, dict) else 0
                try:
                    tool_params = {
                        "ParameterSpace": parameter_space_dict,
                        "ParameterRelationCode": parameter_relation_code,
                    }
                    tool_response, _tool_reward, tool_metrics = await check_valid_instance.execute(
                        current_instance_id, tool_params
                    )
                    resp_str = str(tool_response)
                    space_key = f"space_{idx}"
                    simulation_raw_data.setdefault(
                        space_key,
                        {
                            "parameter_space": parameter_space_dict,
                            "parameter_relation_code": parameter_relation_code,
                            "simulation_data": [],
                        },
                    )
                    if tool_metrics and "simulation_raw_data" in tool_metrics:
                        sim = tool_metrics["simulation_raw_data"]
                        if isinstance(sim, list):
                            simulation_raw_data[space_key]["simulation_data"].extend(sim)
                        elif sim is not None:
                            simulation_raw_data[space_key]["simulation_data"].append(sim)
                    # normalize tool response
                    try:
                        parsed = json.loads(resp_str)
                        if isinstance(parsed, list):
                            for it in parsed:
                                if isinstance(it, dict):
                                    it.pop("comment", None)
                                    it.setdefault("idx", idx)
                                    all_results.append(it)
                                else:
                                    all_results.append({"idx": idx, "result": str(it)})
                        elif isinstance(parsed, dict):
                            parsed.pop("comment", None)
                            parsed.setdefault("idx", idx)
                            all_results.append(parsed)
                        else:
                            all_results.append({"idx": idx, "result": resp_str})
                    except Exception:
                        all_results.append({"idx": idx, "result": resp_str})
                except Exception as e:
                    all_results.append({"idx": idx, "result": f"Error calling {tool_name} for space idx {idx}: {e}"})
            if not all_results:
                all_results = [{"idx": 0, "result": "No spaces to validate"}]
            return (
                False,
                f"<CheckValid>{json.dumps(all_results, ensure_ascii=False)}</CheckValid>",
                0.0,
                {"simulation_raw_data": simulation_raw_data},
            )
        except Exception as e:
            err = f"Error calling {tool_name}: {e}"
            return (
                False,
                f'<CheckValid>[{{"idx": 0, "result": "{err}"}}]</CheckValid>',
                0.0,
                {"simulation_raw_data": {}},
            )
    async def calculate_score(self, instance_id: str, **kwargs) -> float:
        return await super().calculate_score(instance_id, **kwargs)
    async def finalize_interaction(self, instance_id: str, **kwargs) -> bool:
        if instance_id in self._instance_state:
            state = self._instance_state[instance_id]
            context_instance_id_dict = state.get("context_instance_id_dict", {})
            interaction_instances = state.get("interaction_instances", {})
            for name, iid in context_instance_id_dict.items():
                if iid and name in interaction_instances:
                    inst = interaction_instances[name]["instance"]
                    try:
                        await inst.release(iid)
                    except Exception:
                        pass
            del self._instance_state[instance_id]
        return await super().finalize_interaction(instance_id, **kwargs)
