            }
        except Exception as e:
            import traceback
            traceback.print_exc()
            # 在异常情况下，提取 messages 中前两个回合的 content 并拼接
            base_prompt_for_evolve = ""
            try:
                # 从 input_data 中获取 messages
                error_messages = input_data.get("messages", input_data.get("prompt", []))
                if error_messages and len(error_messages) >= 2:
                    first_content = error_messages[0].get("content", "")
                    second_content = error_messages[1].get("content", "")
                    base_prompt_for_evolve = f"{first_content}\n{second_content}"
                elif error_messages and len(error_messages) >= 1:
                    base_prompt_for_evolve = error_messages[0].get("content", "")
            except:
                pass

            # 在 input_data 的 extra_info 中添加 base_prompt_for_evolve
            if "extra_info" not in input_data:
                input_data["extra_info"] = {}
            input_data["extra_info"]["base_prompt_for_evolve"] = base_prompt_for_evolve

